import 'wxt';
import { defineWxtModule, addViteConfig } from 'wxt/modules';
import 'node:path';

const index = defineWxtModule({
  name: "@wxt-dev/webextension-polyfill",
  setup(wxt) {
    addViteConfig(wxt, () => ({
      resolve: {
        alias: {
          "wxt/browser": "@wxt-dev/webextension-polyfill/browser" 
        }
      }
    }));
  }
});

export { index as default };
